import java.util.*;

class Solution {
    public List<Integer> monitor(String[] ops, int[] vals) {
        Map<Long, Integer> cnt = new HashMap<>(); // 记录前缀和出现次数
        long prefixSum = 0;                       // 当前前缀和
        List<Integer> ans = new ArrayList<>();

        for (int i = 0; i < ops.length; i++) {
            if (ops[i].equals("add")) {
                // 当前 prefixSum 可以作为新区间左端点前一位的前缀和
                cnt.put(prefixSum, cnt.getOrDefault(prefixSum, 0) + 1);

                // 加入新的流水数据
                prefixSum += vals[i];
            } else {
                long target = vals[i];

                // 查找满足 prefix[l - 1] = prefixSum - target 的数量
                ans.add(cnt.getOrDefault(prefixSum - target, 0));
            }
        }

        return ans;
    }
}
