```c
/**
 * 实时流处理监控
 * 算法：前缀和 + 哈希表
 * 时间复杂度 O(n)，空间复杂度 O(n)
 */

#define HASH_SIZE 200003

typedef struct Node {
    long long key;
    int val;
    struct Node* next;
} Node;

static Node* hash_table[HASH_SIZE];

static void hash_inc(long long key) {
    unsigned int h = (unsigned int)((key % HASH_SIZE + HASH_SIZE) % HASH_SIZE);
    Node* p = hash_table[h];
    while (p) {
        if (p->key == key) { p->val++; return; }
        p = p->next;
    }
    Node* n = (Node*)malloc(sizeof(Node));
    n->key = key; n->val = 1; n->next = hash_table[h]; hash_table[h] = n;
}

static int hash_get(long long key) {
    unsigned int h = (unsigned int)((key % HASH_SIZE + HASH_SIZE) % HASH_SIZE);
    Node* p = hash_table[h];
    while (p) { if (p->key == key) return p->val; p = p->next; }
    return 0;
}

int* monitor(char** ops, int opsSize, int* vals, int valsSize, int* returnSize) {
    // 初始化哈希表
    memset(hash_table, 0, sizeof(hash_table));

    // 统计查询次数
    int qcnt = 0;
    for (int i = 0; i < opsSize; i++)
        if (strcmp(ops[i], "query") == 0) qcnt++;
    *returnSize = qcnt;
    if (qcnt == 0) return NULL;
    int* ans = (int*)malloc(qcnt * sizeof(int));
    int ans_idx = 0;

    long long prefixSum = 0;

    for (int i = 0; i < opsSize; i++) {
        if (strcmp(ops[i], "add") == 0) {
            // 当前 prefixSum 可作为新区间左端点前一位的前缀和
            hash_inc(prefixSum);
            // 加入新的流水数据
            prefixSum += vals[i];
        } else {
            long long target = vals[i];
            // 需要找 prefix[l-1] = prefixSum - target
            ans[ans_idx++] = hash_get(prefixSum - target);
        }
    }

    // 释放哈希表内存
    for (int i = 0; i < HASH_SIZE; i++) {
        Node* p = hash_table[i];
        while (p) { Node* t = p; p = p->next; free(t); }
    }

    return ans;
}
